{
  "family": "Pfitzner-Moffatt Oxidation",
  "candidate": {
    "substrate_smiles": [
      "CCCCCO"
    ],
    "product_smiles": [
      "CCCCC=O"
    ],
    "optional_reagent_smiles": [
      "CS(C)=O",
      "C1CCCCC(N=C=NC2CCCCC2)C1",
      "Cl.c1cc[nH+]cc1"
    ],
    "rationale": "This example shows the oxidation of a simple primary alcohol (1-pentanol) to the corresponding aldehyde (pentanal). This is a classic textbook transformation for the Pfitzner-Moffatt oxidation. The reagents shown are dimethyl sulfoxide (DMSO), dicyclohexylcarbodiimide (DCC), and pyridinium hydrochloride as the mild acid catalyst, which are the defining components of this named reaction. The use of a simple, acyclic, aliphatic substrate avoids potential side reactions and focuses on the core functional group transformation.",
    "collision_avoidance_note": "The substrate is a simple primary aliphatic alcohol, avoiding complex structures, arenes, or other reactive functional groups that could trigger unrelated named reaction queries (e.g., Swern, Parikh-Doering, Corey-Kim, which also use activated DMSO but different activators). The specific combination of DMSO, a carbodiimide (DCC), and a mild acid catalyst is characteristic of the Pfitzner-Moffatt protocol."
  }
}
